  1160→static int socks_cf_get_select_socks(struct Curl_cfilter *cf,
  1161→                                     struct Curl_easy *data,
  1162→                                     curl_socket_t *socks)
  1163→{
  1164→  struct socks_state *sx = cf->ctx;
